let currentLang=localStorage.getItem('psycalc-lang')||'ru',activeTest='temporistics',sessionId=crypto.randomUUID(),deviceId=localStorage.getItem('psycalc-device-id')||crypto.randomUUID(),startedAt=Date.now(),shownAt={},changed={};localStorage.setItem('psycalc-device-id',deviceId);
