async function hash(s){if(!s)return'';const b=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(s.trim().toLowerCase()));return[...new Uint8Array(b)].map(x=>x.toString(16).padStart(2,'0')).join('')}
function applyLanguage(lang){currentLang=I18N[lang]?lang:'ru';document.documentElement.lang=currentLang;localStorage.setItem('psycalc-lang',currentLang);document.querySelectorAll('[data-i18n]').forEach(el=>{const v=I18N[currentLang][el.dataset.i18n];if(v)el.textContent=v});document.querySelectorAll('[data-lang]').forEach(b=>{const active=b.dataset.lang===currentLang;b.classList.toggle('active',active);b.setAttribute('aria-pressed',String(active))});renderTests()}
function renderTests(){const d=I18N[currentLang],tabs=document.querySelector('#testTabs'),panel=document.querySelector('#testPanel'),test=TESTS[activeTest],items=shuffle(test.items,deviceId+activeTest);shownAt={};changed={};tabs.innerHTML=Object.keys(TESTS).map(k=>`<button class="${k===activeTest?'active':''}" data-test-key="${k}">${TESTS[k].labels[currentLang][0]}</button>`).join('');panel.innerHTML=`<div class="research-card"><b>${d.pilot}</b><p>${d.instruction}</p><label class="consent"><input id="consent" type="checkbox"> ${d.consent}</label></div><div class="metadata-grid"><label>${d.age}<select id="ageBand"><option value="">${d.none}</option><option>under-18</option><option>18-24</option><option>25-34</option><option>35-44</option><option>45-54</option><option>55+</option></select></label><label>${d.exposure}<select id="exposure"><option value="">${d.none}</option><option>none</option><option>beginner</option><option>intermediate</option><option>advanced</option></select></label><label>${d.selftype}<input id="selfType" placeholder="SLI / ЭЛВФ / ..."></label><label>${d.token}<input id="retestToken" type="password" autocomplete="off"></label></div><div class="test-meta"><h3>${test.labels[currentLang][0]}</h3><p>${test.labels[currentLang][1]}</p><p>${test.mode==='socionics'?d.caveatSoc:d.caveatPosition}</p></div><div class="test-items">${items.map((it,i)=>{shownAt[it.id]=Date.now();return`<article class="test-item" data-test-item="${it.id}" data-display-index="${i+1}"><p><b>${i+1}.</b> ${it.text[currentLang]||it.text.ru}</p><div class="scale">${[1,2,3,4,5].map(v=>`<label><input type="radio" name="${it.id}" value="${v}">${v}</label>`).join('')}</div><div class="scale-help"><span>${d.scaleL}</span><span>${d.scaleR}</span></div></article>`}).join('')}</div><div class="test-actions"><button class="primary" data-submit>${d.submit}</button><button data-reset>${d.reset}</button><button data-clear>${d.clear}</button></div><div id="testResult" aria-live="polite"></div>`;tabs.querySelectorAll('[data-test-key]').forEach(b=>b.onclick=()=>{activeTest=b.dataset.testKey;renderTests()});panel.querySelectorAll('input[type=radio]').forEach(r=>r.onchange=()=>changed[r.name]=true);panel.querySelector('[data-submit]').onclick=scoreActiveTest;panel.querySelector('[data-reset]').onclick=renderTests;panel.querySelector('[data-clear]').onclick=()=>{localStorage.removeItem('psycalc-results');document.querySelector('#testResult').innerHTML=''}}
function collect(){const test=TESTS[activeTest],byId=Object.fromEntries(test.items.map(it=>[it.id,it])),scores={},counts={},responses=[];let missing=false,failedAttention=false;document.querySelectorAll('[data-test-item]').forEach(el=>{el.classList.remove('missing-answer');const it=byId[el.dataset.testItem],checked=document.querySelector(`input[name="${it.id}"]:checked`);if(!checked){missing=true;el.classList.add('missing-answer');return}const raw=Number(checked.value),value=it.reverse?6-raw:raw;if(it.attention&&raw!==it.attention)failedAttention=true;if(!it.attention){scores[it.scale]=(scores[it.scale]||0)+value;counts[it.scale]=(counts[it.scale]||0)+1}responses.push({itemId:it.id,itemVersion:it.version,scale:it.scale,attentionExpected:it.attention||null,responseValue:raw,scoredValue:value,displayIndex:Number(el.dataset.displayIndex||0),shownAt:new Date(shownAt[it.id]||startedAt).toISOString(),answeredAt:new Date().toISOString(),responseTimeMs:Date.now()-(shownAt[it.id]||startedAt),changedAnswer:!!changed[it.id]})});return{scores,counts,responses,missing,failedAttention}}
function rowsFor(test,calc){const dims=test.dims||[...new Set(test.items.filter(i=>!i.attention).map(i=>i.scale))];return dims.map(k=>[k,calc.counts[k]?calc.scores[k]/calc.counts[k]:0]).sort((a,b)=>b[1]-a[1])}
function clarity(vals,responses){const gap=(vals[0]?.raw??vals[0]?.[1]??0)-(vals[1]?.raw??vals[1]?.[1]??0),neutral=responses.filter(r=>r.responseValue===3).length/responses.length,straight=new Set(responses.filter(r=>!r.attentionExpected).map(r=>r.responseValue)).size===1;if(straight||neutral>.45||gap<.35)return'low';if(gap<.8||neutral>.25)return'moderate';return'high'}
function socionics(calc){const vals=Object.fromEntries(TESTS.socionics.dims.map(d=>[d,calc.counts[d]?calc.scores[d]/calc.counts[d]:0])),w=[1,.8,.45,.45];return TIMS.map(([code,mbti,names,aspects])=>{const p=Object.fromEntries(TESTS.socionics.dims.map(d=>[d,.12]));aspects.forEach((a,i)=>p[a]=w[i]);return{code,mbti,name:names[currentLang],raw:TESTS.socionics.dims.reduce((s,a)=>s+vals[a]*p[a],0)}}).sort((a,b)=>b.raw-a.raw).slice(0,3)}
