function download(payload){const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`psycalc-${activeTest}-${payload.responseId}.json`;a.click();URL.revokeObjectURL(a.href)}
function renderTests(){const d=I18N[currentLang],tabs=document.querySelector('#testTabs'),panel=document.querySelector('#testPanel'),test=TESTS[activeTest];if(!tabs||!panel)return;const consentAccepted=window.psycalcConsentAccepted===true;tabs.innerHTML=Object.keys(TESTS).map(k=>`<button class="${k===activeTest?'active':''}" data-test-key="${k}">${TESTS[k].labels[currentLang][0]}</button>`).join('');const consentCard=`<div class="research-card"><b>${d.pilot}</b><p>${d.instruction}</p><label class="consent"><input id="consent" type="checkbox" ${consentAccepted?'checked':''}> ${d.consent}</label></div>`;if(!consentAccepted){shownAt={};changed={};panel.innerHTML=`${consentCard}<div class="test-result"><p class="test-caveat">${d.consent}</p></div>`}else{const items=shuffle(test.items,deviceId+activeTest);shownAt={};changed={};panel.innerHTML=`${consentCard}<div class="metadata-grid"><label>${d.age}<select id="ageBand"><option value="">${d.none}</option><option>under-18</option><option>18-24</option><option>25-34</option><option>35-44</option><option>45-54</option><option>55+</option></select></label><label>${d.exposure}<select id="exposure"><option value="">${d.none}</option><option>none</option><option>beginner</option><option>intermediate</option><option>advanced</option></select></label><label>${d.selftype}<input id="selfType" placeholder="SLI / ЭЛВФ / ..."></label><label>${d.token}<input id="retestToken" type="password" autocomplete="off"></label></div><div class="test-meta"><h3>${test.labels[currentLang][0]}</h3><p>${test.labels[currentLang][1]}</p><p>${test.mode==='socionics'?d.caveatSoc:d.caveatPosition}</p></div><div class="test-items">${items.map((it,i)=>{shownAt[it.id]=Date.now();return`<article class="test-item" data-test-item="${it.id}" data-display-index="${i+1}"><p><b>${i+1}.</b> ${it.text[currentLang]||it.text.ru}</p><div class="scale">${[1,2,3,4,5].map(v=>`<label><input type="radio" name="${it.id}" value="${v}">${v}</label>`).join('')}</div><div class="scale-help"><span>${d.scaleL}</span><span>${d.scaleR}</span></div></article>`}).join('')}</div><div class="test-actions"><button class="primary" data-submit>${d.submit}</button><button data-reset>${d.reset}</button><button data-clear>${d.clear}</button></div><div id="testResult" aria-live="polite"></div>`}tabs.querySelectorAll('[data-test-key]').forEach(b=>b.onclick=()=>{activeTest=b.dataset.testKey;renderTests()});panel.querySelector('#consent')?.addEventListener('change',e=>{window.psycalcConsentAccepted=e.target.checked;renderTests()});panel.querySelector('[data-submit]')?.addEventListener('click',scoreActiveTest);panel.querySelector('[data-reset]')?.addEventListener('click',renderTests);panel.querySelector('[data-clear]')?.addEventListener('click',()=>{localStorage.removeItem('psycalc-results');const out=document.querySelector('#testResult');if(out)out.innerHTML=''});panel.querySelectorAll('input[type="radio"]').forEach(r=>r.addEventListener('change',()=>{changed[r.name]=true}))}
function renderTests(){
  const d=I18N[currentLang],tabs=document.querySelector('#testTabs'),panel=document.querySelector('#testPanel'),test=TESTS[activeTest];
  if(!tabs||!panel)return;
  const isResearch=document.body.dataset.testAudience==='research';
  const consentAccepted=window.psycalcConsentAccepted===true;
  const consentCard=`<div class="research-card"><b>${d.pilot}</b><p>${d.instruction}</p><label class="consent"><input id="consent" type="checkbox" ${consentAccepted?'checked':''}> ${d.consent}</label></div>`;
  if(!consentAccepted){
    shownAt={};changed={};
    tabs.innerHTML='';
    panel.innerHTML=`${consentCard}<div class="test-result"><p class="test-caveat">${d.consent}</p></div>`;
  }else{
    const items=shuffle(test.items,deviceId+activeTest);shownAt={};changed={};
    tabs.innerHTML=Object.keys(TESTS).map(k=>`<button class="${k===activeTest?'active':''}" data-test-key="${k}">${TESTS[k].labels[currentLang][0]}</button>`).join('');
    const metadata=isResearch?`<div class="metadata-grid"><label>${d.age}<select id="ageBand"><option value="">${d.none}</option><option>under-18</option><option>18-24</option><option>25-34</option><option>35-44</option><option>45-54</option><option>55+</option></select></label><label>${d.exposure}<select id="exposure"><option value="">${d.none}</option><option>none</option><option>beginner</option><option>intermediate</option><option>advanced</option></select></label><label>${d.selftype}<input id="selfType" placeholder="SLI / ЭЛВФ / ..."></label><label>${d.token}<input id="retestToken" type="password" autocomplete="off"></label></div>`:'';
    const caveat=isResearch?`<p>${test.mode==='socionics'?d.caveatSoc:d.caveatPosition}</p>`:'';
    const clearButton=isResearch?`<button data-clear>${d.clear}</button>`:'';
    panel.innerHTML=`${consentCard}${metadata}<div class="test-meta"><h3>${test.labels[currentLang][0]}</h3><p>${test.labels[currentLang][1]}</p>${caveat}</div><div class="test-items">${items.map((it,i)=>{shownAt[it.id]=Date.now();return`<article class="test-item" data-test-item="${it.id}" data-display-index="${i+1}"><p><b>${i+1}.</b> ${it.text[currentLang]||it.text.ru}</p><div class="scale">${[1,2,3,4,5].map(v=>`<label><input type="radio" name="${it.id}" value="${v}">${v}</label>`).join('')}</div><div class="scale-help"><span>${d.scaleL}</span><span>${d.scaleR}</span></div></article>`}).join('')}</div><div class="test-actions"><button class="primary" data-submit>${d.submit}</button><button data-reset>${d.reset}</button>${clearButton}</div><div id="testResult" aria-live="polite"></div>`;
  }
  tabs.querySelectorAll('[data-test-key]').forEach(b=>b.addEventListener('click',()=>{activeTest=b.dataset.testKey;renderTests()}));
  panel.querySelector('#consent')?.addEventListener('change',e=>{window.psycalcConsentAccepted=e.target.checked;renderTests()});
  panel.querySelectorAll('input[type="radio"]').forEach(i=>i.addEventListener('change',()=>{changed[i.name]=true}));
  panel.querySelector('[data-submit]')?.addEventListener('click',async()=>{await scoreActiveTest();if(!isResearch)document.querySelector('#testResult [data-export]')?.remove();const payload=()=>JSON.parse(localStorage.getItem('psycalc-results')||'null');document.querySelector('#testResult [data-export]')?.addEventListener('click',()=>{const p=payload();if(p)download(p)});document.querySelector('#testResult [data-copy]')?.addEventListener('click',()=>navigator.clipboard?.writeText(payload()?.resultSummary||''))});
  panel.querySelector('[data-reset]')?.addEventListener('click',renderTests);
  panel.querySelector('[data-clear]')?.addEventListener('click',()=>{localStorage.removeItem('psycalc-results');renderTests()});
}
function enhanceControlsA11y(){document.querySelectorAll('[data-lang]').forEach(b=>b.setAttribute('aria-pressed',String(b.dataset.lang===currentLang)));document.querySelectorAll('[data-test-key]').forEach(b=>b.setAttribute('aria-pressed',String(b.dataset.testKey===activeTest)));document.querySelectorAll('button:not([type])').forEach(b=>b.setAttribute('type','button'))}const a11yObserver=new MutationObserver(enhanceControlsA11y);a11yObserver.observe(document.body,{childList:true,subtree:true});document.querySelectorAll('[data-lang]').forEach(b=>b.onclick=()=>applyLanguage(b.dataset.lang));applyLanguage(currentLang);enhanceControlsA11y();
